#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932

int threads_per_block = 512;

long M = 2147483647;
int A = 1103515245;
int C = 12345;

double calcLikelihoodSum(unsigned char * I, int * ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for (x = 0; x < numOnes; x++)
        likelihoodSum += (pow((double) (I[ind[index * numOnes + x]] - 100), 2) - pow((double) (I[ind[index * numOnes + x]] - 228), 2)) / 50.0;
    return likelihoodSum;
}

void cdfCalc(double * CDF, double * weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

double d_randu(int * seed, int index) {
    long M_local = 2147483647;
    int A_local = 1103515245;
    int C_local = 12345;
    int num = A_local * seed[index] + C_local;
    seed[index] = num % M_local;
    return fabs(seed[index] / ((double) M_local));
}

double d_randn(int * seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

int findIndexBin(double * CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex;
    while (endIndex > beginIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (CDF[middleIndex] >= value) {
            if (middleIndex == 0)
                return middleIndex;
            else if (CDF[middleIndex - 1] < value)
                return middleIndex;
            else if (CDF[middleIndex - 1] == value) {
                while (CDF[middleIndex] == value && middleIndex >= 0)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (CDF[middleIndex] > value)
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

double dev_round_double(double value) {
    int newValue = (int) (value);
    if (value - newValue < 0.5)
        return (double) newValue;
    else
        return (double) (newValue + 1);
}

__kernel void find_index_kernel(double * arrayX, double * arrayY, double * CDF, double * u, double * xj, double * yj, double * weights, int Nparticles) {
    int i = get_global_id(0);

    if (i < Nparticles) {
        int index = -1;
        int x;

        for (x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

__kernel void normalize_weights_kernel(double * weights, int Nparticles, double* partial_sums, double * CDF, double * u, int * seed) {
    int i = get_global_id(0);

    double u1, sumWeights;

    if(i == 0)
        sumWeights = partial_sums[0];

    if (i < Nparticles) {
        weights[i] = weights[i] / sumWeights;
    }

    if (i == 0) {
        cdfCalc(CDF, weights, Nparticles);
        u[0] = (1.0 / ((double) (Nparticles))) * d_randu(seed, 0); 
    }

    if(i == 0) 
        u1 = u[0];

    if (i < Nparticles) {
        u[i] = u1 + i / ((double) (Nparticles));
    }
}

__kernel void sum_kernel(double* partial_sums, int Nparticles) {
    int i = get_global_id(0);

    if (i == 0) {
        int x;
        double sum = 0.0;
        int num_blocks = (Nparticles + threads_per_block - 1) / threads_per_block;
        for (x = 0; x < num_blocks; x++) {
            sum += partial_sums[x];
        }
        partial_sums[0] = sum;
    }
}

__kernel void likelihood_kernel(double * arrayX, double * arrayY, double * xj, double * yj, double * CDF, int * ind, int * objxy, double * likelihood, unsigned char * I, double * u, double * weights, int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr, int *seed, double* partial_sums) {
    int i = get_global_id(0);
    int y;

    int indX, indY; 

    if (i < Nparticles) {
        arrayX[i] = xj[i]; 
        arrayY[i] = yj[i]; 

        weights[i] = 1.0 / ((double) (Nparticles)); 

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);
    }

    if (i < Nparticles) {
        for (y = 0; y < countOnes; y++) {
            indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];

            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);

        likelihood[i] = likelihood[i] / countOnes;

        weights[i] = weights[i] * exp(likelihood[i]); 
    }

    double buffer[512];
    buffer[0] = 0.0;

    if (i < Nparticles) {
        buffer[0] = weights[i];
    }

    partial_sums[i] = buffer[0];
}

